() => {
  const allDivs = document.querySelectorAll('div');
  for (const div of allDivs) {
    const style = div.getAttribute('style') || '';
    if (style.includes('height: 32px') && style.includes('border-bottom')) {
      const labels = div.querySelectorAll('div[title*="Click to navigate"]');
      const results = [];
      for (const label of labels) {
        const rect = label.getBoundingClientRect();
        const computedStyle = getComputedStyle(label);
        results.push({
          text: label.textContent,
          title: label.getAttribute('title'),
          left: computedStyle.left,
          rect: { x: rect.x, y: rect.y, width: rect.width, height: rect.height },
          zIndex: computedStyle.zIndex,
          backgroundColor: computedStyle.backgroundColor
        });
      }
      return { labels: results, parentRect: div.getBoundingClientRect() };
    }
  }
  return { error: 'not found' };
}

