/**
 * StatsMonitor - Simple FPS/MS/Memory monitor using stats.js
 *
 * This is a reliable fallback for r3f-perf when it has compatibility issues.
 *
 * Usage:
 * - Shows real-time FPS, frame time (MS), and memory usage (MB)
 * - Toggle panels by clicking on the stats panel
 * - Press 'S' key to toggle visibility
 *
 * Integration:
 * - Import and add <StatsMonitor /> inside your component (NOT inside Canvas)
 * - For R3F: Use the StatsR3F component inside the Canvas
 */

import { useEffect, useRef, useState, useCallback } from 'react';
import { useFrame } from '@react-three/fiber';
import Stats from 'stats.js';

// ─────────────────────────────────────────────────────────────
// STATS MONITOR (for use outside Canvas)
// ─────────────────────────────────────────────────────────────

interface StatsMonitorProps {
  /** Whether the stats panel is visible */
  visible?: boolean;
  /** Position of the panel */
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
}

/**
 * Stats monitor component using stats.js
 * Render this OUTSIDE the R3F Canvas
 */
export function StatsMonitor({ visible = true, position = 'top-left' }: StatsMonitorProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const statsRef = useRef<Stats | null>(null);
  const frameIdRef = useRef<number>(0);

  useEffect(() => {
    if (!visible || !containerRef.current) return;

    // Create stats instance
    const stats = new Stats();
    stats.showPanel(0); // 0: fps, 1: ms, 2: mb
    statsRef.current = stats;

    // Style the container
    const dom = stats.dom;
    dom.style.position = 'relative';
    dom.style.top = '0';
    dom.style.left = '0';

    containerRef.current.appendChild(dom);

    // Animation loop for stats update
    let lastTime = performance.now();
    const animate = () => {
      const currentTime = performance.now();
      // Only update stats if enough time has passed (throttle to ~60fps)
      if (currentTime - lastTime >= 16) {
        stats.update();
        lastTime = currentTime;
      }
      frameIdRef.current = requestAnimationFrame(animate);
    };
    frameIdRef.current = requestAnimationFrame(animate);

    return () => {
      if (frameIdRef.current) {
        cancelAnimationFrame(frameIdRef.current);
      }
      if (containerRef.current && dom.parentNode === containerRef.current) {
        containerRef.current.removeChild(dom);
      }
      statsRef.current = null;
    };
  }, [visible]);

  if (!visible) return null;

  const positionStyles: React.CSSProperties = {
    position: 'fixed',
    zIndex: 10000,
    ...(position === 'top-left' && { top: 50, left: 0 }),
    ...(position === 'top-right' && { top: 50, right: 0 }),
    ...(position === 'bottom-left' && { bottom: 0, left: 0 }),
    ...(position === 'bottom-right' && { bottom: 0, right: 0 }),
  };

  return <div ref={containerRef} style={positionStyles} />;
}

// ─────────────────────────────────────────────────────────────
// STATS R3F (for use inside Canvas - updates with R3F render loop)
// ─────────────────────────────────────────────────────────────

interface StatsR3FProps {
  /** Reference to a Stats instance created outside */
  stats: Stats;
}

/**
 * R3F component that updates stats on each frame
 * Must be used inside R3F Canvas
 */
export function StatsR3F({ stats }: StatsR3FProps) {
  useFrame(() => {
    stats.update();
  });
  return null;
}

// ─────────────────────────────────────────────────────────────
// HOOK FOR TOGGLE
// ─────────────────────────────────────────────────────────────

/**
 * Hook to toggle stats visibility with 'S' key
 */
export function useStatsToggle(initialVisible = true) {
  const [visible, setVisible] = useState(initialVisible);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (
        e.key === 's' &&
        !e.ctrlKey &&
        !e.metaKey &&
        !e.altKey &&
        !(e.target instanceof HTMLInputElement) &&
        !(e.target instanceof HTMLTextAreaElement)
      ) {
        setVisible(v => !v);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const toggle = useCallback(() => setVisible(v => !v), []);

  return { visible, toggle, setVisible };
}

// ─────────────────────────────────────────────────────────────
// COMBINED MONITOR (Stats + Custom Metrics)
// ─────────────────────────────────────────────────────────────

interface PerformancePanelProps {
  visible?: boolean;
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
  /** Custom metrics to display */
  customMetrics?: Record<string, number | string>;
}

/**
 * Combined performance panel with FPS + custom metrics
 */
export function PerformancePanel({
  visible = true,
  position = 'top-left',
  customMetrics = {}
}: PerformancePanelProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const statsRef = useRef<Stats | null>(null);
  const frameIdRef = useRef<number>(0);
  const [fps, setFps] = useState(0);
  const [ms, setMs] = useState(0);
  const fpsHistoryRef = useRef<number[]>([]);

  useEffect(() => {
    if (!visible) return;

    const stats = new Stats();
    stats.showPanel(0);
    statsRef.current = stats;

    let lastTime = performance.now();
    let frames = 0;

    const animate = () => {
      const currentTime = performance.now();
      frames++;

      // Update FPS every second
      if (currentTime - lastTime >= 1000) {
        const currentFps = Math.round(frames * 1000 / (currentTime - lastTime));
        const currentMs = Math.round((currentTime - lastTime) / frames * 100) / 100;

        setFps(currentFps);
        setMs(currentMs);

        // Keep FPS history for averaging
        fpsHistoryRef.current.push(currentFps);
        if (fpsHistoryRef.current.length > 60) {
          fpsHistoryRef.current.shift();
        }

        frames = 0;
        lastTime = currentTime;
      }

      stats.update();
      frameIdRef.current = requestAnimationFrame(animate);
    };

    frameIdRef.current = requestAnimationFrame(animate);

    return () => {
      if (frameIdRef.current) {
        cancelAnimationFrame(frameIdRef.current);
      }
      statsRef.current = null;
    };
  }, [visible]);

  if (!visible) return null;

  const positionStyles: React.CSSProperties = {
    position: 'fixed',
    zIndex: 10000,
    padding: '8px',
    background: 'rgba(0, 0, 0, 0.8)',
    color: '#0f0',
    fontFamily: 'monospace',
    fontSize: '12px',
    borderRadius: '4px',
    ...(position === 'top-left' && { top: 50, left: 8 }),
    ...(position === 'top-right' && { top: 50, right: 8 }),
    ...(position === 'bottom-left' && { bottom: 8, left: 8 }),
    ...(position === 'bottom-right' && { bottom: 8, right: 8 }),
  };

  const avgFps = fpsHistoryRef.current.length > 0
    ? Math.round(fpsHistoryRef.current.reduce((a, b) => a + b, 0) / fpsHistoryRef.current.length)
    : fps;

  return (
    <div style={positionStyles}>
      <div style={{ color: fps >= 55 ? '#0f0' : fps >= 30 ? '#ff0' : '#f00' }}>
        FPS: {fps} (avg: {avgFps})
      </div>
      <div>MS: {ms.toFixed(2)}</div>
      {Object.entries(customMetrics).map(([key, value]) => (
        <div key={key}>{key}: {value}</div>
      ))}
    </div>
  );
}

