import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import {
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Button,
  ButtonGroup,
  Tag,
  Card,
  Intent,
  Alignment,
  OverlayToaster,
  Position,
} from '@blueprintjs/core';
import type { Toaster } from '@blueprintjs/core';
import { InfiniteCanvas } from './canvas/InfiniteCanvas';
import type { ViewportInfo, NavigationTarget } from './canvas/InfiniteCanvas';
import { TimelineHeader } from './components/TimelineHeader';
import { TaskTooltip } from './components/TaskTooltip';
import { TaskDetailsPanel } from './components/TaskDetailsPanel';
import { Minimap } from './components/Minimap';
import { usePerfMonitorToggle } from './components/PerfMonitor';
import type { PerfEvent } from './components/PerfMonitor';
import { PerformancePanel } from './components/StatsMonitor';
import { useCanvasSelector } from './state';
import { DEFAULT_VIEW_CONFIG } from './data/types';
import { getRenderData } from './data/generator';

type LOD = 'MACRO' | 'MESO' | 'MICRO';

// Number of trains to display in sidebar
const TRAIN_COUNT = 50;
const TOTAL_DAYS = 365 * 10; // 10 years
const { pxPerTrain, pxPerDay } = DEFAULT_VIEW_CONFIG;

// Sidebar width constant - used for TimelineHeader offset
const SIDEBAR_WIDTH = 130;

function App() {
  const [zoom, setZoom] = useState(1.0);
  // Dynamic min zoom calculated by InfiniteCanvas based on world bounds
  const [minZoom, setMinZoom] = useState(0.1);
  // viewportTopY: the Y coordinate of the TOP of the viewport in world space
  // 0 = top of TRAIN-001, -24 = top of TRAIN-002, etc.
  const [viewportTopY, setViewportTopY] = useState(0);
  // Viewport X bounds for timeline header
  const [viewportLeftX, setViewportLeftX] = useState(0);
  const [viewportRightX, setViewportRightX] = useState(1000);

  // Animated zoom target (for smooth button zoom)
  const [animatedZoomTarget, setAnimatedZoomTarget] = useState<number | null>(null);

  // Navigation target for sidebar/timeline clicks (F124)
  const [navigationTarget, setNavigationTarget] = useState<NavigationTarget | null>(null);

  // Performance monitor toggle (PERF-001)
  const { visible: perfVisible, toggle: togglePerf } = usePerfMonitorToggle(
    process.env.NODE_ENV === 'development'
  );

  // Performance event tracking for logging context
  const [isPanning, setIsPanning] = useState(false);
  const [isZooming, setIsZooming] = useState(false);
  const prevLod = useRef<LOD>('MESO');

  // Mouse position for tooltip (F020)
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  // BUG-004: Removed minimapVisible state - minimap is now always visible (Google Maps style)

  // Get hovered task ID from canvas state (F020)
  const hoveredTaskId = useCanvasSelector((s) => s.interaction.hoveredTaskId);

  // Get camera position from canvas state for minimap (F025)
  const canvasCameraX = useCanvasSelector((s) => s.viewport.camera.x);
  const canvasCameraY = useCanvasSelector((s) => s.viewport.camera.y);
  const canvasSizeFromStore = useCanvasSelector((s) => s.viewport.canvasSize);

  // Get render data for minimap (F025)
  const { tasks } = useMemo(() => getRenderData(), []);

  // Instructions toaster ref
  const toasterRef = useRef<Toaster | null>(null);

  // Show instructions on first load
  useEffect(() => {
    let isMounted = true;

    // Create toaster instance (async in BlueprintJS 6)
    OverlayToaster.createAsync({
      position: Position.TOP,
      className: 'instructions-toaster',
    }).then((toaster) => {
      if (!isMounted) return;
      toasterRef.current = toaster;

      // Show instruction toast with 5 second auto-dismiss
      toaster.show({
        message: '🖱️ Scroll to zoom  •  Drag to pan  •  Double-click to zoom in',
        intent: Intent.PRIMARY,
        timeout: 5000,
        icon: 'info-sign',
      });
    });

    // Cleanup: clear toaster on unmount
    return () => {
      isMounted = false;
      toasterRef.current?.clear();
    };
  }, []);

  // Compute LOD from zoom level
  const getLOD = (z: number): LOD => {
    if (z < 0.5) return 'MACRO';
    if (z > 2.0) return 'MICRO';
    return 'MESO';
  };

  const lod = getLOD(zoom);

  const getLODIntent = (l: LOD): Intent => {
    switch (l) {
      case 'MACRO': return Intent.WARNING;
      case 'MESO': return Intent.PRIMARY;
      case 'MICRO': return Intent.SUCCESS;
    }
  };

  // Button handlers use animated zoom for smooth transitions
  const handleZoomIn = () => setAnimatedZoomTarget(Math.min(zoom * 1.5, 5.0));
  const handleZoomOut = () => setAnimatedZoomTarget(Math.max(zoom / 1.5, minZoom));
  const handleMinZoomChange = useCallback((newMinZoom: number) => {
    setMinZoom(newMinZoom);
  }, []);
  const handleReset = () => {
    setAnimatedZoomTarget(1.0);
    setViewportTopY(0);
  };
  const handleAnimatedZoomComplete = useCallback(() => {
    setAnimatedZoomTarget(null);
  }, []);

  // F124: Navigation handlers for sidebar and timeline clicks
  const handleNavigateToTrain = useCallback((trainIndex: number) => {
    setNavigationTarget({ trainIndex });
  }, []);

  const handleNavigateToDate = useCallback((dayOffset: number) => {
    setNavigationTarget({ dayOffset });
  }, []);

  const handleNavigationComplete = useCallback(() => {
    setNavigationTarget(null);
  }, []);

  // F025: Minimap navigation - navigate to world coordinates
  const handleMinimapNavigate = useCallback((worldX: number, worldY: number) => {
    // Convert world coordinates to day offset and train index
    const dayOffset = worldX / pxPerDay;
    const trainIndex = -worldY / pxPerTrain; // Y is negative in world

    // Navigate to the position
    setNavigationTarget({
      dayOffset: Math.max(0, dayOffset),
      trainIndex: Math.max(0, Math.min(TRAIN_COUNT - 1, Math.round(trainIndex))),
    });
  }, []);

  // BUG-004: Removed handleMinimapToggle - minimap is now always visible (Google Maps style)

  const handleZoomChange = useCallback((newZoom: number) => {
    setZoom(newZoom);
    // Track zooming state for perf logging
    setIsZooming(true);
    // Reset zooming after brief delay
    const timeout = setTimeout(() => setIsZooming(false), 100);
    return () => clearTimeout(timeout);
  }, []);

  const handleViewportChange = useCallback((viewport: ViewportInfo) => {
    setViewportTopY(viewport.topY);
    setViewportLeftX(viewport.leftX);
    setViewportRightX(viewport.rightX);
    // Track panning state for perf logging
    setIsPanning(true);
    // Reset panning after brief delay
    const timeout = setTimeout(() => setIsPanning(false), 100);
    return () => clearTimeout(timeout);
  }, []);

  // Determine current performance event for logging
  const getCurrentPerfEvent = useCallback((): PerfEvent => {
    const currentLod = getLOD(zoom);
    if (prevLod.current !== currentLod) {
      prevLod.current = currentLod;
      return 'lod_transition';
    }
    if (animatedZoomTarget != null || navigationTarget != null) {
      return 'animating';
    }
    if (isZooming) return 'zooming';
    if (isPanning) return 'panning';
    return 'idle';
  }, [zoom, animatedZoomTarget, navigationTarget, isZooming, isPanning]);

  const perfEvent = getCurrentPerfEvent();

  // Calculate sidebar offset to align with canvas
  // viewportTopY = 0 means TRAIN-001 is at the top
  // viewportTopY = -24 means TRAIN-002 is at the top
  // Sidebar offset = -viewportTopY (positive value scrolls down)
  const rowHeight = pxPerTrain * zoom;
  const sidebarOffset = viewportTopY * zoom;

  return (
    <div style={{ height: '100vh', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Navbar with app title and zoom controls */}
      <Navbar fixedToTop={false}>
        <NavbarGroup align={Alignment.LEFT}>
          <NavbarHeading>
            <strong>MMS</strong> Canvas
          </NavbarHeading>
          <NavbarDivider />
          <span style={{ fontFamily: 'monospace', fontSize: 13 }}>
            Zoom: {zoom.toFixed(2)}x
          </span>
          <NavbarDivider />
          <Tag intent={getLODIntent(lod)} minimal large>
            {lod}
          </Tag>
        </NavbarGroup>
        <NavbarGroup align={Alignment.RIGHT}>
          <ButtonGroup minimal>
            <Button icon="minus" onClick={handleZoomOut} title="Zoom Out" />
            <Button icon="plus" onClick={handleZoomIn} title="Zoom In" />
          </ButtonGroup>
          <NavbarDivider />
          <Button icon="reset" minimal onClick={handleReset}>
            Reset View
          </Button>
          <NavbarDivider />
          <Button
            icon="dashboard"
            minimal
            active={perfVisible}
            onClick={togglePerf}
            title="Toggle Performance Monitor (P)"
          >
            Perf
          </Button>
        </NavbarGroup>
      </Navbar>

      {/* Timeline header - positioned above canvas, offset by sidebar width */}
      <TimelineHeader
        viewportLeftX={viewportLeftX}
        viewportRightX={viewportRightX}
        zoom={zoom}
        sidebarWidth={SIDEBAR_WIDTH}
        onDateClick={handleNavigateToDate}
      />

      {/* Main content area with sidebar and canvas */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', minHeight: 0 }}>
        {/* Train sidebar using BlueprintJS Card */}
        <Card
          elevation={1}
          style={{
            width: SIDEBAR_WIDTH,
            borderRadius: 0,
            padding: 0,
            flexShrink: 0,
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
          }}
        >
          {/* Sidebar header */}
          <div
            style={{
              padding: '10px 12px',
              borderBottom: '1px solid #e1e8ed',
              backgroundColor: '#f5f8fa',
              fontWeight: 600,
              fontSize: 13,
            }}
          >
            Trains
          </div>

          {/* Scrollable train list - synced with canvas panY (BUG-002 fix: overflow auto) */}
          <div
            style={{
              flex: 1,
              overflow: 'auto',
              position: 'relative',
            }}
          >
            <div
              style={{
                position: 'absolute',
                top: sidebarOffset,
                left: 0,
                right: 0,
              }}
            >
              {Array.from({ length: TRAIN_COUNT }, (_, i) => (
                <div
                  key={i}
                  onClick={() => handleNavigateToTrain(i)}
                  style={{
                    height: rowHeight,
                    padding: '0 12px',
                    fontSize: 12,
                    fontFamily: 'monospace',
                    display: 'flex',
                    alignItems: 'center',
                    borderBottom: '1px solid #f0f0f0',
                    backgroundColor: i % 2 === 0 ? '#ffffff' : '#fafafa',
                    cursor: 'pointer',
                    transition: 'background-color 0.15s ease',
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#e1e8ed';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = i % 2 === 0 ? '#ffffff' : '#fafafa';
                  }}
                  title={`Click to navigate to TRAIN-${String(i + 1).padStart(3, '0')}`}
                >
                  TRAIN-{String(i + 1).padStart(3, '0')}
                </div>
              ))}
            </div>
          </div>
        </Card>

        {/* R3F Canvas area */}
        <div
          style={{ flex: 1, position: 'relative', minWidth: 0 }}
          onMouseMove={(e) => setMousePos({ x: e.clientX, y: e.clientY })}
        >
          <InfiniteCanvas
            zoom={zoom}
            lod={lod}
            onZoomChange={handleZoomChange}
            onViewportChange={handleViewportChange}
            onMinZoomChange={handleMinZoomChange}
            animatedZoomTarget={animatedZoomTarget}
            onAnimatedZoomComplete={handleAnimatedZoomComplete}
            navigationTarget={navigationTarget}
            onNavigationComplete={handleNavigationComplete}
            perfVisible={perfVisible}
            perfEvent={perfEvent}
          />

          {/* Minimap (F025, BUG-004) - bird's eye navigation - always visible (Google Maps style) */}
          <Minimap
            trainCount={TRAIN_COUNT}
            totalDays={TOTAL_DAYS}
            tasks={tasks}
            cameraX={canvasCameraX}
            cameraY={canvasCameraY}
            zoom={zoom}
            canvasWidth={canvasSizeFromStore.width || 800}
            canvasHeight={canvasSizeFromStore.height || 600}
            onNavigate={handleMinimapNavigate}
          />
        </div>
      </div>

      {/* Task tooltip (F020) - shown on hover */}
      <TaskTooltip
        taskId={hoveredTaskId}
        mouseX={mousePos.x}
        mouseY={mousePos.y}
      />

      {/* Task details panel (F026) - shown on selection */}
      <TaskDetailsPanel />

      {/* Performance panel - reliable FPS monitor using stats.js */}
      <PerformancePanel
        visible={perfVisible}
        position="top-left"
      />
    </div>
  );
}

export default App;

